css_styles:
:root {
    --land-bg: #FAFAF7;
    --land-surface: #FFFFFF;
    --land-text-main: #2B302D;
    --land-text-muted: #5C6660;
    --land-sage: #7A9180;
    --land-sage-dark: #4A5C50;
    --land-sage-light: #EAF0EB;
    --land-coral: #E07A5F;
    --land-coral-hover: #D1674A;
    --land-status-normal-text: #3F5C47;
    --land-status-normal-bg: #EAF0EB;
    --land-status-high-text: #993C24;
    --land-status-high-bg: #FCEEEB;
    --land-status-low-text: #915A24;
    --land-status-low-bg: #FDF4EB;
    --land-status-border-text: #91761F;
    --land-status-border-bg: #FDF8EB;
}

body {
    background-color: var(--land-bg);
    color: var(--land-text-main);
    font-family: 'Plus Jakarta Sans', sans-serif;
}

h1, h2, h3, h4, h5, h6, .land-hero-title {
    font-family: 'Outfit', sans-serif;
    color: var(--land-text-main);
    letter-spacing: -0.02em;
}

.text-main { color: var(--land-text-main) !important; }
.text-sage { color: var(--land-sage) !important; }
.text-coral { color: var(--land-coral) !important; }
.bg-sage-light { background-color: var(--land-sage-light) !important; }
.bg-sage { background-color: var(--land-sage) !important; }
.border-sage-light { border-color: #DDE5E0 !important; }

.btn-coral {
    background-color: var(--land-coral);
    color: white;
    border: none;
    transition: transform 0.2s ease, background-color 0.2s ease, box-shadow 0.2s ease;
}
.btn-coral:hover {
    background-color: var(--land-coral-hover);
    color: white;
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(224, 122, 95, 0.3);
}

.btn-outline-sage {
    background-color: transparent;
    color: var(--land-sage-dark);
    border: 2px solid var(--land-sage);
    transition: all 0.2s ease;
}
.btn-outline-sage:hover {
    background-color: var(--land-sage-light);
    color: var(--land-sage-dark);
    transform: translateY(-2px);
}

.land-status-normal { background-color: var(--land-status-normal-bg); color: var(--land-status-normal-text); border: 1px solid rgba(63,92,71,0.2); }
.land-status-high { background-color: var(--land-status-high-bg); color: var(--land-status-high-text); border: 1px solid rgba(153,60,36,0.2); }
.land-status-low { background-color: var(--land-status-low-bg); color: var(--land-status-low-text); border: 1px solid rgba(145,90,36,0.2); }
.land-status-borderline { background-color: var(--land-status-border-bg); color: var(--land-status-border-text); border: 1px solid rgba(145,118,31,0.2); }

.pulse-dot {
    width: 8px;
    height: 8px;
    animation: pulse 2s infinite;
}

@keyframes pulse {
    0% { transform: scale(0.95); box-shadow: 0 0 0 0 rgba(122, 145, 128, 0.7); }
    70% { transform: scale(1); box-shadow: 0 0 0 6px rgba(122, 145, 128, 0); }
    100% { transform: scale(0.95); box-shadow: 0 0 0 0 rgba(122, 145, 128, 0); }
}

.land-data-grid > div:not(:last-child) {
    border-bottom: 1px dashed var(--land-sage-light);
}

.land-eyebrow {
    background-color: var(--land-sage-light);
    color: var(--land-sage-dark);
    font-weight: 600;
    font-size: 0.875rem;
    letter-spacing: 0.05em;
    text-transform: uppercase;
}

.land-hero-visual {
    max-width: 500px;
}
